class Solution:
    def kthCharacter(self, k: int, operations: List[int]) -> str:
        word = "a"
        for op in operations:
            if op == 0:
                word += word
            else:
                word = ''.join(chr(ord(c) + 1) if c != 'z' else 'a' for c in word)
        return word[k-1]

